#!/usr/bin/expect -f
set timeout 600
log_file -a /tmp/serial.log

spawn qemu-system-x86_64 -m 1024 -smp 2 \
  -drive file=/app/alpine-disk.qcow2,if=virtio,format=qcow2 \
  -cdrom /app/alpine.iso -boot d \
  -nic user,hostfwd=tcp::2222-:22 \
  -nographic

# run a command in the guest and wait for completion marker
proc run {cmd} {
    send -- "$cmd\r"
    send -- "echo DN-\$?-EOK\r"
    expect {
        -re {DN-[0-9]+-EOK} {}
        timeout { puts "\n### TIMEOUT: $cmd\n" }
    }
}

# wait for login prompt then log in as root (no password)
expect {
    -re {login: ?$} { send -- "root\r" }
    timeout { puts "### no login prompt"; exit 1 }
}
expect -re {[#\$] $}

# bring up networking (qemu user-net DHCP -> 10.0.2.15)
run "ip link set eth0 up"
run "udhcpc -i eth0 -q -t 8"
run "ip -4 addr show eth0"

# set root password to password123
send -- "passwd root\r"
expect {
    -re {(?i)new password} { send -- "password123\r" }
    timeout { puts "### passwd no prompt" }
}
expect {
    -re {(?i)retype|(?i)re-enter|(?i)again} { send -- "password123\r" }
    timeout {}
}
expect -re {[#\$] $}

# ensure openssh is available (from cdrom repo if not preinstalled)
run "command -v sshd || (find /media -name APKINDEX.tar.gz -printf '%h\\n' | head -1 > /tmp/repo; echo /media/cdrom/apks >> /etc/apk/repositories; cat /tmp/repo >> /etc/apk/repositories; apk update; apk add openssh)"
run "command -v sshd"

# configure sshd for root password login
run "sed -i 's/^#\\?PermitRootLogin.*/PermitRootLogin yes/' /etc/ssh/sshd_config"
run "grep -q '^PermitRootLogin yes' /etc/ssh/sshd_config || echo 'PermitRootLogin yes' >> /etc/ssh/sshd_config"
run "sed -i 's/^#\\?PasswordAuthentication.*/PasswordAuthentication yes/' /etc/ssh/sshd_config"
run "grep -q '^PasswordAuthentication yes' /etc/ssh/sshd_config || echo 'PasswordAuthentication yes' >> /etc/ssh/sshd_config"

# host keys + start sshd
run "ssh-keygen -A"
run "/usr/sbin/sshd"
run "sleep 1; netstat -tln 2>/dev/null | grep ':22 ' || ss -tln | grep ':22 '"
run "echo SSHD_SETUP_COMPLETE"

# keep qemu running
set timeout -1
expect eof

